import{c as t}from"./app.8935f5f1.js";const e={},n=t('<h2 id="_60util" tabindex="-1"><a class="header-anchor" href="#_60util" aria-hidden="true">#</a> 60util</h2><p>1.邮箱</p><div class="language-text ext-text"><pre class="language-text"><code>export const isEmail = (s) =&gt; {\n    return /^([a-zA-Z0-9_-])+@([a-zA-Z0-9_-])+((.[a-zA-Z0-9_-]{2,3}){1,2})$/.test(s)\n}\n</code></pre></div><p>2.手机号码</p><div class="language-text ext-text"><pre class="language-text"><code>export const isMobile = (s) =&gt; {\n    return /^1[0-9]{10}$/.test(s)\n}\n</code></pre></div><p>3.电话号码</p><div class="language-text ext-text"><pre class="language-text"><code>export const isPhone = (s) =&gt; {\n    return /^([0-9]{3,4}-)?[0-9]{7,8}$/.test(s)\n}\n</code></pre></div><p>4.是否url地址</p><div class="language-text ext-text"><pre class="language-text"><code>export const isURL = (s) =&gt; {\n    return /^http[s]?:\\/\\/.*/.test(s)\n}\n</code></pre></div><p>5.是否字符串</p><div class="language-text ext-text"><pre class="language-text"><code>export const isString = (o) =&gt; {\n    return Object.prototype.toString.call(o).slice(8, -1) === &#39;String&#39;\n}\n</code></pre></div><p>6.是否数字</p><div class="language-text ext-text"><pre class="language-text"><code>export const isNumber = (o) =&gt; {\n    return Object.prototype.toString.call(o).slice(8, -1) === &#39;Number&#39;\n}\n</code></pre></div><p>7.是否boolean</p><div class="language-text ext-text"><pre class="language-text"><code>export const isBoolean = (o) =&gt; {\n    return Object.prototype.toString.call(o).slice(8, -1) === &#39;Boolean&#39;\n}\n</code></pre></div><p>8.是否函数</p><div class="language-text ext-text"><pre class="language-text"><code>export const isFunction = (o) =&gt; {\n    return Object.prototype.toString.call(o).slice(8, -1) === &#39;Function&#39;\n}\n</code></pre></div><p>9.是否为null</p><div class="language-text ext-text"><pre class="language-text"><code>export const isNull = (o) =&gt; {\n    return Object.prototype.toString.call(o).slice(8, -1) === &#39;Null&#39;\n}\n</code></pre></div><p>10.是否undefined</p><div class="language-text ext-text"><pre class="language-text"><code>export const isUndefined = (o) =&gt; {\n    return Object.prototype.toString.call(o).slice(8, -1) === &#39;Undefined&#39;\n}\n</code></pre></div><p>11.是否对象</p><div class="language-text ext-text"><pre class="language-text"><code>export const isObj = (o) =&gt; {\n    return Object.prototype.toString.call(o).slice(8, -1) === &#39;Object&#39;\n}\n</code></pre></div><p>12.是否数组</p><div class="language-text ext-text"><pre class="language-text"><code>export const isArray = (o) =&gt; {\n    return Object.prototype.toString.call(o).slice(8, -1) === &#39;Array&#39;\n}\n</code></pre></div><p>13.是否时间</p><div class="language-text ext-text"><pre class="language-text"><code>export const isDate = (o) =&gt; {\n    return Object.prototype.toString.call(o).slice(8, -1) === &#39;Date&#39;\n}\n</code></pre></div><p>14.是否正则</p><div class="language-text ext-text"><pre class="language-text"><code>export const isRegExp = (o) =&gt; {\n    return Object.prototype.toString.call(o).slice(8, -1) === &#39;RegExp&#39;\n}\n</code></pre></div><p>15.是否错误对象</p><div class="language-text ext-text"><pre class="language-text"><code>export const isError = (o) =&gt; {\n    return Object.prototype.toString.call(o).slice(8, -1) === &#39;Error&#39;\n}\n</code></pre></div><p>16.是否Symbol函数</p><div class="language-text ext-text"><pre class="language-text"><code>export const isSymbol = (o) =&gt; {\n    return Object.prototype.toString.call(o).slice(8, -1) === &#39;Symbol&#39;\n}\n</code></pre></div><p>17.是否Promise对象</p><div class="language-text ext-text"><pre class="language-text"><code>export const isPromise = (o) =&gt; {\n    return Object.prototype.toString.call(o).slice(8, -1) === &#39;Promise&#39;\n}\n</code></pre></div><p>18.是否Set对象</p><div class="language-text ext-text"><pre class="language-text"><code>export const isSet = (o) =&gt; {\n    return Object.prototype.toString.call(o).slice(8, -1) === &#39;Set&#39;\n}\nexport const ua = navigator.userAgent.toLowerCase();\n</code></pre></div><p>19.是否是微信浏览器</p><div class="language-text ext-text"><pre class="language-text"><code>export const isWeiXin = () =&gt; {\n    return ua.match(/microMessenger/i) == &#39;micromessenger&#39;\n}\n</code></pre></div><p>20.是否是移动端</p><div class="language-text ext-text"><pre class="language-text"><code>export const isDeviceMobile = () =&gt; {\n    return /android|webos|iphone|ipod|balckberry/i.test(ua)\n}\n</code></pre></div><p>21.是否是QQ浏览器</p><div class="language-text ext-text"><pre class="language-text"><code>export const isQQBrowser = () =&gt; {\n    return !!ua.match(/mqqbrowser|qzone|qqbrowser|qbwebviewtype/i)\n}\n</code></pre></div><p>22.是否是爬虫</p><div class="language-text ext-text"><pre class="language-text"><code>export const isSpider = () =&gt; {\n    return /adsbot|googlebot|bingbot|msnbot|yandexbot|baidubot|robot|careerbot|seznambot|bot|baiduspider|jikespider|symantecspider|scannerlwebcrawler|crawler|360spider|sosospider|sogou web sprider|sogou orion spider/.test(ua)\n}\n</code></pre></div><p>23.是否ios</p><div class="language-text ext-text"><pre class="language-text"><code>export const isIos = () =&gt; {\n    var u = navigator.userAgent;\n    if (u.indexOf(&#39;Android&#39;) &gt; -1 || u.indexOf(&#39;Linux&#39;) &gt; -1) {  //安卓手机\n        return false\n    } else if (u.indexOf(&#39;iPhone&#39;) &gt; -1) {//苹果手机\n        return true\n    } else if (u.indexOf(&#39;iPad&#39;) &gt; -1) {//iPad\n        return false\n    } else if (u.indexOf(&#39;Windows Phone&#39;) &gt; -1) {//winphone手机\n        return false\n    } else {\n        return false\n    }\n}\n</code></pre></div><p>24.是否为PC端</p><div class="language-text ext-text"><pre class="language-text"><code>export const isPC = () =&gt; {\n    var userAgentInfo = navigator.userAgent;\n    var Agents = [&quot;Android&quot;, &quot;iPhone&quot;,\n        &quot;SymbianOS&quot;, &quot;Windows Phone&quot;,\n        &quot;iPad&quot;, &quot;iPod&quot;];\n    var flag = true;\n    for (var v = 0; v &lt; Agents.length; v++) {\n        if (userAgentInfo.indexOf(Agents[v]) &gt; 0) {\n            flag = false;\n            break;\n        }\n    }\n    return flag;\n}\n</code></pre></div><p>25.去除html标签</p><div class="language-text ext-text"><pre class="language-text"><code>export const removeHtmltag = (str) =&gt; {\n    return str.replace(/&lt;[^&gt;]+&gt;/g, &#39;&#39;)\n}\n</code></pre></div><p>26.获取url参数</p><div class="language-text ext-text"><pre class="language-text"><code>export const getQueryString = (name) =&gt; {\n    const reg = new RegExp(&#39;(^|&amp;)&#39; + name + &#39;=([^&amp;]*)(&amp;|$)&#39;, &#39;i&#39;);\n    const search = window.location.search.split(&#39;?&#39;)[1] || &#39;&#39;;\n    const r = search.match(reg) || [];\n    return r[2];\n}\n</code></pre></div><p>27.动态引入js</p><div class="language-text ext-text"><pre class="language-text"><code>export const injectScript = (src) =&gt; {\n    const s = document.createElement(&#39;script&#39;);\n    s.type = &#39;text/javascript&#39;;\n    s.async = true;\n    s.src = src;\n    const t = document.getElementsByTagName(&#39;script&#39;)[0];\n    t.parentNode.insertBefore(s, t);\n}\n</code></pre></div><p>28.根据url地址下载</p><div class="language-text ext-text"><pre class="language-text"><code>export const download = (url) =&gt; {\n    var isChrome = navigator.userAgent.toLowerCase().indexOf(&#39;chrome&#39;) &gt; -1;\n    var isSafari = navigator.userAgent.toLowerCase().indexOf(&#39;safari&#39;) &gt; -1;\n    if (isChrome || isSafari) {\n        var link = document.createElement(&#39;a&#39;);\n        link.href = url;\n        if (link.download !== undefined) {\n            var fileName = url.substring(url.lastIndexOf(&#39;/&#39;) + 1, url.length);\n            link.download = fileName;\n        }\n        if (document.createEvent) {\n            var e = document.createEvent(&#39;MouseEvents&#39;);\n            e.initEvent(&#39;click&#39;, true, true);\n            link.dispatchEvent(e);\n            return true;\n        }\n    }\n    if (url.indexOf(&#39;?&#39;) === -1) {\n        url += &#39;?download&#39;;\n    }\n    window.open(url, &#39;_self&#39;);\n    return true;\n}\n</code></pre></div><p>29.el是否包含某个class</p><div class="language-text ext-text"><pre class="language-text"><code>export const hasClass = (el, className) =&gt; {\n    let reg = new RegExp(&#39;(^|\\\\s)&#39; + className + &#39;(\\\\s|$)&#39;)\n    return reg.test(el.className)\n}\n</code></pre></div><p>30.el添加某个class</p><div class="language-text ext-text"><pre class="language-text"><code>export const addClass = (el, className) =&gt; {\n    if (hasClass(el, className)) {\n        return\n    }\n    let newClass = el.className.split(&#39; &#39;)\n    newClass.push(className)\n    el.className = newClass.join(&#39; &#39;)\n}\n</code></pre></div><p>31.el去除某个class</p><div class="language-text ext-text"><pre class="language-text"><code>export const removeClass = (el, className) =&gt; {\n    if (!hasClass(el, className)) {\n        return\n    }\n    let reg = new RegExp(&#39;(^|\\\\s)&#39; + className + &#39;(\\\\s|$)&#39;, &#39;g&#39;)\n    el.className = el.className.replace(reg, &#39; &#39;)\n}\n</code></pre></div><p>32.获取滚动的坐标</p><div class="language-text ext-text"><pre class="language-text"><code>export const getScrollPosition = (el = window) =&gt; ({\n    x: el.pageXOffset !== undefined ? el.pageXOffset : el.scrollLeft,\n    y: el.pageYOffset !== undefined ? el.pageYOffset : el.scrollTop\n});\n</code></pre></div><p>33.滚动到顶部</p><div class="language-text ext-text"><pre class="language-text"><code>export const scrollToTop = () =&gt; {\n    const c = document.documentElement.scrollTop || document.body.scrollTop;\n    if (c &gt; 0) {\n        window.requestAnimationFrame(scrollToTop);\n        window.scrollTo(0, c - c / 8);\n    }\n}\n</code></pre></div><p>34.el是否在视口范围内</p><div class="language-text ext-text"><pre class="language-text"><code>export const elementIsVisibleInViewport = (el, partiallyVisible = false) =&gt; {\n    const { top, left, bottom, right } = el.getBoundingClientRect();\n    const { innerHeight, innerWidth } = window;\n    return partiallyVisible\n        ? ((top &gt; 0 &amp;&amp; top &lt; innerHeight) || (bottom &gt; 0 &amp;&amp; bottom &lt; innerHeight)) &amp;&amp;\n        ((left &gt; 0 &amp;&amp; left &lt; innerWidth) || (right &gt; 0 &amp;&amp; right &lt; innerWidth))\n        : top &gt;= 0 &amp;&amp; left &gt;= 0 &amp;&amp; bottom &lt;= innerHeight &amp;&amp; right &lt;= innerWidth;\n}\n</code></pre></div><p>35.洗牌算法随机</p><div class="language-text ext-text"><pre class="language-text"><code>export const shuffle = (arr) =&gt; {\n    var result = [],\n        random;\n    while (arr.length &gt; 0) {\n        random = Math.floor(Math.random() * arr.length);\n        result.push(arr[random])\n        arr.splice(random, 1)\n    }\n    return result;\n}\n</code></pre></div><p>36.拦截粘贴板</p><div class="language-text ext-text"><pre class="language-text"><code>export const copyTextToClipboard = (value) =&gt; {\n    var textArea = document.createElement(&quot;textarea&quot;);\n    textArea.style.background = &#39;transparent&#39;;\n    textArea.value = value;\n    document.body.appendChild(textArea);\n    textArea.select();\n    try {\n        var successful = document.execCommand(&#39;copy&#39;);\n    } catch (err) {\n        console.log(&#39;Oops, unable to copy&#39;);\n    }\n    document.body.removeChild(textArea);\n}\n</code></pre></div><p>37.判断类型集合</p><div class="language-text ext-text"><pre class="language-text"><code>export const checkStr = (str, type) =&gt; {\n    switch (type) {\n        case &#39;phone&#39;:   //手机号码\n            return /^1[3|4|5|6|7|8|9][0-9]{9}$/.test(str);\n        case &#39;tel&#39;:     //座机\n            return /^(0\\d{2,3}-\\d{7,8})(-\\d{1,4})?$/.test(str);\n        case &#39;card&#39;:    //身份证\n            return /(^\\d{15}$)|(^\\d{18}$)|(^\\d{17}(\\d|X|x)$)/.test(str);\n        case &#39;pwd&#39;:     //密码以字母开头，长度在6~18之间，只能包含字母、数字和下划线\n            return /^[a-zA-Z]\\w{5,17}$/.test(str)\n        case &#39;postal&#39;:  //邮政编码\n            return /[1-9]\\d{5}(?!\\d)/.test(str);\n        case &#39;QQ&#39;:      //QQ号\n            return /^[1-9][0-9]{4,9}$/.test(str);\n        case &#39;email&#39;:   //邮箱\n            return /^[\\w-]+(\\.[\\w-]+)*@[\\w-]+(\\.[\\w-]+)+$/.test(str);\n        case &#39;money&#39;:   //金额(小数点2位)\n            return /^\\d*(?:\\.\\d{0,2})?$/.test(str);\n        case &#39;URL&#39;:     //网址\n            return /(http|ftp|https):\\/\\/[\\w\\-_]+(\\.[\\w\\-_]+)+([\\w\\-\\.,@?^=%&amp;:/~\\+#]*[\\w\\-\\@?^=%&amp;/~\\+#])?/.test(str)\n        case &#39;IP&#39;:      //IP\n            return /((?:(?:25[0-5]|2[0-4]\\\\d|[01]?\\\\d?\\\\d)\\\\.){3}(?:25[0-5]|2[0-4]\\\\d|[01]?\\\\d?\\\\d))/.test(str);\n        case &#39;date&#39;:    //日期时间\n            return /^(\\d{4})\\-(\\d{2})\\-(\\d{2}) (\\d{2})(?:\\:\\d{2}|:(\\d{2}):(\\d{2}))$/.test(str) || /^(\\d{4})\\-(\\d{2})\\-(\\d{2})$/.test(str)\n        case &#39;number&#39;:  //数字\n            return /^[0-9]$/.test(str);\n        case &#39;english&#39;: //英文\n            return /^[a-zA-Z]+$/.test(str);\n        case &#39;chinese&#39;: //中文\n            return /^[\\\\u4E00-\\\\u9FA5]+$/.test(str);\n        case &#39;lower&#39;:   //小写\n            return /^[a-z]+$/.test(str);\n        case &#39;upper&#39;:   //大写\n            return /^[A-Z]+$/.test(str);\n        case &#39;HTML&#39;:    //HTML标记\n            return /&lt;(&quot;[^&quot;]*&quot;|&#39;[^&#39;]*&#39;|[^&#39;&quot;&gt;])*&gt;/.test(str);\n        default:\n            return true;\n    }\n}\n</code></pre></div><p>38.严格的身份证校验</p><div class="language-text ext-text"><pre class="language-text"><code>export const isCardID = (sId) =&gt; {\n    if (!/(^\\d{15}$)|(^\\d{17}(\\d|X|x)$)/.test(sId)) {\n        console.log(&#39;你输入的身份证长度或格式错误&#39;)\n        return false\n    }\n    //身份证城市\n    var aCity = { 11: &quot;北京&quot;, 12: &quot;天津&quot;, 13: &quot;河北&quot;, 14: &quot;山西&quot;, 15: &quot;内蒙古&quot;, 21: &quot;辽宁&quot;, 22: &quot;吉林&quot;, 23: &quot;黑龙江&quot;, 31: &quot;上海&quot;, 32: &quot;江苏&quot;, 33: &quot;浙江&quot;, 34: &quot;安徽&quot;, 35: &quot;福建&quot;, 36: &quot;江西&quot;, 37: &quot;山东&quot;, 41: &quot;河南&quot;, 42: &quot;湖北&quot;, 43: &quot;湖南&quot;, 44: &quot;广东&quot;, 45: &quot;广西&quot;, 46: &quot;海南&quot;, 50: &quot;重庆&quot;, 51: &quot;四川&quot;, 52: &quot;贵州&quot;, 53: &quot;云南&quot;, 54: &quot;西藏&quot;, 61: &quot;陕西&quot;, 62: &quot;甘肃&quot;, 63: &quot;青海&quot;, 64: &quot;宁夏&quot;, 65: &quot;新疆&quot;, 71: &quot;台湾&quot;, 81: &quot;香港&quot;, 82: &quot;澳门&quot;, 91: &quot;国外&quot; };\n    if (!aCity[parseInt(sId.substr(0, 2))]) {\n        console.log(&#39;你的身份证地区非法&#39;)\n        return false\n    }\n\n    // 出生日期验证\n    var sBirthday = (sId.substr(6, 4) + &quot;-&quot; + Number(sId.substr(10, 2)) + &quot;-&quot; + Number(sId.substr(12, 2))).replace(/-/g, &quot;/&quot;),\n        d = new Date(sBirthday)\n    if (sBirthday != (d.getFullYear() + &quot;/&quot; + (d.getMonth() + 1) + &quot;/&quot; + d.getDate())) {\n        console.log(&#39;身份证上的出生日期非法&#39;)\n        return false\n    }\n\n    // 身份证号码校验\n    var sum = 0,\n        weights = [7, 9, 10, 5, 8, 4, 2, 1, 6, 3, 7, 9, 10, 5, 8, 4, 2],\n        codes = &quot;10X98765432&quot;\n    for (var i = 0; i &lt; sId.length - 1; i++) {\n        sum += sId[i] * weights[i];\n    }\n    var last = codes[sum % 11]; //计算出来的最后一位身份证号码\n    if (sId[sId.length - 1] != last) {\n        console.log(&#39;你输入的身份证号非法&#39;)\n        return false\n    }\n\n    return true\n}\n</code></pre></div><p>39.随机数范围</p><div class="language-text ext-text"><pre class="language-text"><code>export const random = (min, max) =&gt; {\n    if (arguments.length === 2) {\n        return Math.floor(min + Math.random() * ((max + 1) - min))\n    } else {\n        return null;\n    }\n}\n</code></pre></div><p>40.将阿拉伯数字翻译成中文的大写数字</p><div class="language-text ext-text"><pre class="language-text"><code>export const numberToChinese = (num) =&gt; {\n    var AA = new Array(&quot;零&quot;, &quot;一&quot;, &quot;二&quot;, &quot;三&quot;, &quot;四&quot;, &quot;五&quot;, &quot;六&quot;, &quot;七&quot;, &quot;八&quot;, &quot;九&quot;, &quot;十&quot;);\n    var BB = new Array(&quot;&quot;, &quot;十&quot;, &quot;百&quot;, &quot;仟&quot;, &quot;萬&quot;, &quot;億&quot;, &quot;点&quot;, &quot;&quot;);\n    var a = (&quot;&quot; + num).replace(/(^0*)/g, &quot;&quot;).split(&quot;.&quot;),\n        k = 0,\n        re = &quot;&quot;;\n    for (var i = a[0].length - 1; i &gt;= 0; i--) {\n        switch (k) {\n            case 0:\n                re = BB[7] + re;\n                break;\n            case 4:\n                if (!new RegExp(&quot;0{4}//d{&quot; + (a[0].length - i - 1) + &quot;}$&quot;)\n                    .test(a[0]))\n                    re = BB[4] + re;\n                break;\n            case 8:\n                re = BB[5] + re;\n                BB[7] = BB[5];\n                k = 0;\n                break;\n        }\n        if (k % 4 == 2 &amp;&amp; a[0].charAt(i + 2) != 0 &amp;&amp; a[0].charAt(i + 1) == 0)\n            re = AA[0] + re;\n        if (a[0].charAt(i) != 0)\n            re = AA[a[0].charAt(i)] + BB[k % 4] + re;\n        k++;\n    }\n\n    if (a.length &gt; 1) // 加上小数部分(如果有小数部分)\n    {\n        re += BB[6];\n        for (var i = 0; i &lt; a[1].length; i++)\n            re += AA[a[1].charAt(i)];\n    }\n    if (re == &#39;一十&#39;)\n        re = &quot;十&quot;;\n    if (re.match(/^一/) &amp;&amp; re.length == 3)\n        re = re.replace(&quot;一&quot;, &quot;&quot;);\n    return re;\n}\n</code></pre></div><p>41.将数字转换为大写金额</p><div class="language-text ext-text"><pre class="language-text"><code>export const changeToChinese = (Num) =&gt; {\n    //判断如果传递进来的不是字符的话转换为字符\n    if (typeof Num == &quot;number&quot;) {\n        Num = new String(Num);\n    };\n    Num = Num.replace(/,/g, &quot;&quot;) //替换tomoney()中的“,”\n    Num = Num.replace(/ /g, &quot;&quot;) //替换tomoney()中的空格\n    Num = Num.replace(/￥/g, &quot;&quot;) //替换掉可能出现的￥字符\n    if (isNaN(Num)) { //验证输入的字符是否为数字\n        //alert(&quot;请检查小写金额是否正确&quot;);\n        return &quot;&quot;;\n    };\n    //字符处理完毕后开始转换，采用前后两部分分别转换\n    var part = String(Num).split(&quot;.&quot;);\n    var newchar = &quot;&quot;;\n    //小数点前进行转化\n    for (var i = part[0].length - 1; i &gt;= 0; i--) {\n        if (part[0].length &gt; 10) {\n            return &quot;&quot;;\n            //若数量超过拾亿单位，提示\n        }\n        var tmpnewchar = &quot;&quot;\n        var perchar = part[0].charAt(i);\n        switch (perchar) {\n            case &quot;0&quot;:\n                tmpnewchar = &quot;零&quot; + tmpnewchar;\n                break;\n            case &quot;1&quot;:\n                tmpnewchar = &quot;壹&quot; + tmpnewchar;\n                break;\n            case &quot;2&quot;:\n                tmpnewchar = &quot;贰&quot; + tmpnewchar;\n                break;\n            case &quot;3&quot;:\n                tmpnewchar = &quot;叁&quot; + tmpnewchar;\n                break;\n            case &quot;4&quot;:\n                tmpnewchar = &quot;肆&quot; + tmpnewchar;\n                break;\n            case &quot;5&quot;:\n                tmpnewchar = &quot;伍&quot; + tmpnewchar;\n                break;\n            case &quot;6&quot;:\n                tmpnewchar = &quot;陆&quot; + tmpnewchar;\n                break;\n            case &quot;7&quot;:\n                tmpnewchar = &quot;柒&quot; + tmpnewchar;\n                break;\n            case &quot;8&quot;:\n                tmpnewchar = &quot;捌&quot; + tmpnewchar;\n                break;\n            case &quot;9&quot;:\n                tmpnewchar = &quot;玖&quot; + tmpnewchar;\n                break;\n        }\n        switch (part[0].length - i - 1) {\n            case 0:\n                tmpnewchar = tmpnewchar + &quot;元&quot;;\n                break;\n            case 1:\n                if (perchar != 0) tmpnewchar = tmpnewchar + &quot;拾&quot;;\n                break;\n            case 2:\n                if (perchar != 0) tmpnewchar = tmpnewchar + &quot;佰&quot;;\n                break;\n            case 3:\n                if (perchar != 0) tmpnewchar = tmpnewchar + &quot;仟&quot;;\n                break;\n            case 4:\n                tmpnewchar = tmpnewchar + &quot;万&quot;;\n                break;\n            case 5:\n                if (perchar != 0) tmpnewchar = tmpnewchar + &quot;拾&quot;;\n                break;\n            case 6:\n                if (perchar != 0) tmpnewchar = tmpnewchar + &quot;佰&quot;;\n                break;\n            case 7:\n                if (perchar != 0) tmpnewchar = tmpnewchar + &quot;仟&quot;;\n                break;\n            case 8:\n                tmpnewchar = tmpnewchar + &quot;亿&quot;;\n                break;\n            case 9:\n                tmpnewchar = tmpnewchar + &quot;拾&quot;;\n                break;\n        }\n        var newchar = tmpnewchar + newchar;\n    }\n    //小数点之后进行转化\n    if (Num.indexOf(&quot;.&quot;) != -1) {\n        if (part[1].length &gt; 2) {\n            // alert(&quot;小数点之后只能保留两位,系统将自动截断&quot;);\n            part[1] = part[1].substr(0, 2)\n        }\n        for (i = 0; i &lt; part[1].length; i++) {\n            tmpnewchar = &quot;&quot;\n            perchar = part[1].charAt(i)\n            switch (perchar) {\n                case &quot;0&quot;:\n                    tmpnewchar = &quot;零&quot; + tmpnewchar;\n                    break;\n                case &quot;1&quot;:\n                    tmpnewchar = &quot;壹&quot; + tmpnewchar;\n                    break;\n                case &quot;2&quot;:\n                    tmpnewchar = &quot;贰&quot; + tmpnewchar;\n                    break;\n                case &quot;3&quot;:\n                    tmpnewchar = &quot;叁&quot; + tmpnewchar;\n                    break;\n                case &quot;4&quot;:\n                    tmpnewchar = &quot;肆&quot; + tmpnewchar;\n                    break;\n                case &quot;5&quot;:\n                    tmpnewchar = &quot;伍&quot; + tmpnewchar;\n                    break;\n                case &quot;6&quot;:\n                    tmpnewchar = &quot;陆&quot; + tmpnewchar;\n                    break;\n                case &quot;7&quot;:\n                    tmpnewchar = &quot;柒&quot; + tmpnewchar;\n                    break;\n                case &quot;8&quot;:\n                    tmpnewchar = &quot;捌&quot; + tmpnewchar;\n                    break;\n                case &quot;9&quot;:\n                    tmpnewchar = &quot;玖&quot; + tmpnewchar;\n                    break;\n            }\n            if (i == 0) tmpnewchar = tmpnewchar + &quot;角&quot;;\n            if (i == 1) tmpnewchar = tmpnewchar + &quot;分&quot;;\n            newchar = newchar + tmpnewchar;\n        }\n    }\n    //替换所有无用汉字\n    while (newchar.search(&quot;零零&quot;) != -1)\n        newchar = newchar.replace(&quot;零零&quot;, &quot;零&quot;);\n    newchar = newchar.replace(&quot;零亿&quot;, &quot;亿&quot;);\n    newchar = newchar.replace(&quot;亿万&quot;, &quot;亿&quot;);\n    newchar = newchar.replace(&quot;零万&quot;, &quot;万&quot;);\n    newchar = newchar.replace(&quot;零元&quot;, &quot;元&quot;);\n    newchar = newchar.replace(&quot;零角&quot;, &quot;&quot;);\n    newchar = newchar.replace(&quot;零分&quot;, &quot;&quot;);\n    if (newchar.charAt(newchar.length - 1) == &quot;元&quot;) {\n        newchar = newchar + &quot;整&quot;\n    }\n    return newchar;\n}\n</code></pre></div><p>42.判断一个元素是否在数组中</p><div class="language-text ext-text"><pre class="language-text"><code>export const contains = (arr, val) =&gt; {\n    return arr.indexOf(val) != -1 ? true : false;\n}\n</code></pre></div><p>43.数组排序，<code>{type} 1：从小到大 2：从大到小 3：随机</code></p><div class="language-text ext-text"><pre class="language-text"><code>export const sort = (arr, type = 1) =&gt; {\n    return arr.sort((a, b) =&gt; {\n        switch (type) {\n            case 1:\n                return a - b;\n            case 2:\n                return b - a;\n            case 3:\n                return Math.random() - 0.5;\n            default:\n                return arr;\n        }\n    })\n}\n</code></pre></div><p>44.去重</p><div class="language-text ext-text"><pre class="language-text"><code>export const unique = (arr) =&gt; {\n    if (Array.hasOwnProperty(&#39;from&#39;)) {\n        return Array.from(new Set(arr));\n    } else {\n        var n = {}, r = [];\n        for (var i = 0; i &lt; arr.length; i++) {\n            if (!n[arr[i]]) {\n                n[arr[i]] = true;\n                r.push(arr[i]);\n            }\n        }\n        return r;\n    }\n}\n</code></pre></div><p>45.求两个集合的并集</p><div class="language-text ext-text"><pre class="language-text"><code>export const union = (a, b) =&gt; {\n    var newArr = a.concat(b);\n    return this.unique(newArr);\n}\n</code></pre></div><p>46.求两个集合的交集</p><div class="language-text ext-text"><pre class="language-text"><code>export const intersect = (a, b) =&gt; {\n    var _this = this;\n    a = this.unique(a);\n    return this.map(a, function (o) {\n        return _this.contains(b, o) ? o : null;\n    });\n}\n</code></pre></div><p>47.删除其中一个元素</p><div class="language-text ext-text"><pre class="language-text"><code>export const remove = (arr, ele) =&gt; {\n    var index = arr.indexOf(ele);\n    if (index &gt; -1) {\n        arr.splice(index, 1);\n    }\n    return arr;\n}\n</code></pre></div><p>48.将类数组转换为数组</p><div class="language-text ext-text"><pre class="language-text"><code>export const formArray = (ary) =&gt; {\n    var arr = [];\n    if (Array.isArray(ary)) {\n        arr = ary;\n    } else {\n        arr = Array.prototype.slice.call(ary);\n    };\n    return arr;\n}\n</code></pre></div><p>49.最大值</p><div class="language-text ext-text"><pre class="language-text"><code>export const max = (arr) =&gt; {\n    return Math.max.apply(null, arr);\n}\n</code></pre></div><p>50.最小值</p><div class="language-text ext-text"><pre class="language-text"><code>export const min = (arr) =&gt; {\n    return Math.min.apply(null, arr);\n}\n</code></pre></div><p>51.求和</p><div class="language-text ext-text"><pre class="language-text"><code>export const sum = (arr) =&gt; {\n    return arr.reduce((pre, cur) =&gt; {\n        return pre + cur\n    })\n}\n</code></pre></div><p>52.平均值</p><div class="language-text ext-text"><pre class="language-text"><code>export const average = (arr) =&gt; {\n    return this.sum(arr) / arr.length\n}\n</code></pre></div><p>53.去除空格,<code>type: 1-所有空格 2-前后空格 3-前空格 4-后空格</code></p><div class="language-text ext-text"><pre class="language-text"><code>export const trim = (str, type) =&gt; {\n    type = type || 1\n    switch (type) {\n        case 1:\n            return str.replace(/\\s+/g, &quot;&quot;);\n        case 2:\n            return str.replace(/(^\\s*)|(\\s*$)/g, &quot;&quot;);\n        case 3:\n            return str.replace(/(^\\s*)/g, &quot;&quot;);\n        case 4:\n            return str.replace(/(\\s*$)/g, &quot;&quot;);\n        default:\n            return str;\n    }\n}\n</code></pre></div><p>54.字符转换，<code>type: 1:首字母大写 2：首字母小写 3：大小写转换 4：全部大写 5：全部小写</code></p><div class="language-text ext-text"><pre class="language-text"><code>export const changeCase = (str, type) =&gt; {\n    type = type || 4\n    switch (type) {\n        case 1:\n            return str.replace(/\\b\\w+\\b/g, function (word) {\n                return word.substring(0, 1).toUpperCase() + word.substring(1).toLowerCase();\n\n            });\n        case 2:\n            return str.replace(/\\b\\w+\\b/g, function (word) {\n                return word.substring(0, 1).toLowerCase() + word.substring(1).toUpperCase();\n            });\n        case 3:\n            return str.split(&#39;&#39;).map(function (word) {\n                if (/[a-z]/.test(word)) {\n                    return word.toUpperCase();\n                } else {\n                    return word.toLowerCase()\n                }\n            }).join(&#39;&#39;)\n        case 4:\n            return str.toUpperCase();\n        case 5:\n            return str.toLowerCase();\n        default:\n            return str;\n    }\n}\n</code></pre></div><p>55.检测密码强度</p><div class="language-text ext-text"><pre class="language-text"><code>export const checkPwd = (str) =&gt; {\n    var Lv = 0;\n    if (str.length &lt; 6) {\n        return Lv\n    }\n    if (/[0-9]/.test(str)) {\n        Lv++\n    }\n    if (/[a-z]/.test(str)) {\n        Lv++\n    }\n    if (/[A-Z]/.test(str)) {\n        Lv++\n    }\n    if (/[\\.|-|_]/.test(str)) {\n        Lv++\n    }\n    return Lv;\n}\n</code></pre></div><p>56.函数节流器</p><div class="language-text ext-text"><pre class="language-text"><code>export const debouncer = (fn, time, interval = 200) =&gt; {\n    if (time - (window.debounceTimestamp || 0) &gt; interval) {\n        fn &amp;&amp; fn();\n        window.debounceTimestamp = time;\n    }\n}\n</code></pre></div><p>57.在字符串中插入新字符串</p><div class="language-text ext-text"><pre class="language-text"><code>export const insertStr = (soure, index, newStr) =&gt; {\n    var str = soure.slice(0, index) + newStr + soure.slice(index);\n    return str;\n}\n</code></pre></div><p>58.判断两个对象是否键值相同</p><div class="language-text ext-text"><pre class="language-text"><code>export const isObjectEqual = (a, b) =&gt; {\n    var aProps = Object.getOwnPropertyNames(a);\n    var bProps = Object.getOwnPropertyNames(b);\n\n    if (aProps.length !== bProps.length) {\n        return false;\n    }\n\n    for (var i = 0; i &lt; aProps.length; i++) {\n        var propName = aProps[i];\n\n        if (a[propName] !== b[propName]) {\n            return false;\n        }\n    }\n    return true;\n}\n</code></pre></div><p>59.16进制颜色转RGBRGBA字符串</p><div class="language-text ext-text"><pre class="language-text"><code>export const colorToRGB = (val, opa) =&gt; {\n\n    var pattern = /^(#?)[a-fA-F0-9]{6}$/; //16进制颜色值校验规则\n    var isOpa = typeof opa == &#39;number&#39;; //判断是否有设置不透明度\n\n    if (!pattern.test(val)) { //如果值不符合规则返回空字符\n        return &#39;&#39;;\n    }\n\n    var v = val.replace(/#/, &#39;&#39;); //如果有#号先去除#号\n    var rgbArr = [];\n    var rgbStr = &#39;&#39;;\n\n    for (var i = 0; i &lt; 3; i++) {\n        var item = v.substring(i * 2, i * 2 + 2);\n        var num = parseInt(item, 16);\n        rgbArr.push(num);\n    }\n\n    rgbStr = rgbArr.join();\n    rgbStr = &#39;rgb&#39; + (isOpa ? &#39;a&#39; : &#39;&#39;) + &#39;(&#39; + rgbStr + (isOpa ? &#39;,&#39; + opa : &#39;&#39;) + &#39;)&#39;;\n    return rgbStr;\n}\n</code></pre></div><p>60.追加url参数</p><div class="language-text ext-text"><pre class="language-text"><code>export const appendQuery = (url, key, value) =&gt; {\n    var options = key;\n    if (typeof options == &#39;string&#39;) {\n        options = {};\n        options[key] = value;\n    }\n    options = $.param(options);\n    if (url.includes(&#39;?&#39;)) {\n        url += &#39;&amp;&#39; + options\n    } else {\n        url += &#39;?&#39; + options\n    }\n    return url;\n}\n</code></pre></div>',121);e.render=function(t,e){return n};export{e as default};
